import{_ as r}from"./chunks/serbija_order_screenshot.wr7iINSk.js";import{_ as a,c as t,o as i,ag as o}from"./chunks/framework.DRADY2L-.js";const u=JSON.parse('{"title":"Памятка участников FPV in Serbia","description":"Здесь собраны заметки FPV сообщества Сербии: карта спотов, ссылки на чаты, правила для полетов и многое другое. По закону все очень лайтово: до 900 грамм - 1...","frontmatter":{"description":"Здесь собраны заметки FPV сообщества Сербии: карта спотов, ссылки на чаты, правила для полетов и многое другое. По закону все очень лайтово: до 900 грамм - 1...","gitAuthors":["mituritsyn","Valentina Petrenko","ikherty"]},"headers":[],"relativePath":"ru/theworld/Serbija.md","filePath":"ru/theworld/Serbija.md","lastUpdated":1728390730000}'),l={name:"ru/theworld/Serbija.md"};function p(n,e,s,h,d,b){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="памятка-участников-fpv-in-serbia" tabindex="-1">Памятка участников FPV in Serbia <a class="header-anchor" href="#памятка-участников-fpv-in-serbia" aria-label="Permalink to &quot;Памятка участников FPV in Serbia&quot;">​</a></h1><p>Здесь собраны заметки FPV сообщества Сербии: карта спотов, ссылки на чаты, правила для полетов и многое другое.</p><h2 id="законы" tabindex="-1">Законы <a class="header-anchor" href="#законы" aria-label="Permalink to &quot;Законы&quot;">​</a></h2><p>По закону все очень лайтово:</p><p>до 900 грамм - 1 категория, нужно регать, только если:</p><ul><li>летаешь выше 100 метров,</li><li>около аэродромов,</li><li>500+ метров от себя,</li><li>над людьми,</li><li>рядом с людьми (30м),</li><li>около запрещенных зон,</li><li>ночью,</li><li>дрон что-то перевозит.</li></ul><p>👉 <a href="https://cad.gov.rs/upload/Bespilotni%20vazduhoplovi/Pravilnik_o_bespilotnim_vazduhoplovima_Sl_glasnik_RS_broj_108-15-nova-eng.pdf" target="_blank" rel="noreferrer">Ссылка на закон</a></p><h2 id="чаты-сервера" tabindex="-1">Чаты, сервера <a class="header-anchor" href="#чаты-сервера" aria-label="Permalink to &quot;Чаты, сервера&quot;">​</a></h2><p>👉 <a href="https://forms.gle/cth6sK1sMgeXBMg8A" target="_blank" rel="noreferrer">FPV in Serbia, основной чат для общения русскоговорящих пилотов в телеграме</a></p><p>👉 <a href="https://t.me/fpvserbia" target="_blank" rel="noreferrer">FPV Serbia 🇷🇸, чат для общения на английском в телеграме (мало активный)</a></p><p>👉 <a href="https://invite.viber.com/?g2=AQB9gM56j3yFlEs4e%2F7A94xbBJcwGi7nr5CTWxWHJXALXGFkZTGxQX4rYcpHe5Dz" target="_blank" rel="noreferrer">FPV Srbija, чат для общения на сербском в Viber</a></p><p>👉 <a href="https://invite.viber.com/?g2=AQAimw9t307HcUs3whI3srAvqUWrYAAoMDVUc7qpP4%2B4wZbSl%2BdMHDDY5RK8nt3V" target="_blank" rel="noreferrer">RC BERZA, барахолка на сербском в Viber</a></p><p>👉 <a href="https://selective-tarragon-f1b.notion.site/FPV-3aaf0c40d79b44f398d7982da1cf2b33?pvs=4" target="_blank" rel="noreferrer">Барахолка русскоговорящего комьюнити</a></p><p>👉 <a href="https://discord.gg/3W55nkAA" target="_blank" rel="noreferrer">Discord сервер для полётов в симуляторах</a></p><p>👉 <a href="https://fpv.rs/" target="_blank" rel="noreferrer">Сербский форум (мало активный)</a></p><h2 id="карты" tabindex="-1">Карты <a class="header-anchor" href="#карты" aria-label="Permalink to &quot;Карты&quot;">​</a></h2><p>🗺️ <a href="https://cad.gov.rs/lat/strana/23311/bespilotni-vazduhoplovi" target="_blank" rel="noreferrer">Официальная карта бесполетных зон</a></p><p>🗺️ <a href="https://maps.app.goo.gl/HJ2VQ9K3NeJfHJ3XA" target="_blank" rel="noreferrer">Карта FPV спотов на google maps (можно редактировать)</a></p><p>🗺️ <a href="https://www.bpl.rs/en/approved-flights-map/" target="_blank" rel="noreferrer">Еще одна карта с бесполетными зонами</a></p><p>По мнению Sergei Orekhov, топ мест, куда было бы круто добраться на тачке для полетушек:</p><p>Из далеких:</p><ol><li>Национальный парк Тара - на границе с боснией возле черногории (3,5 часа на машине из Белграда);</li><li>Национальный парк Фрушка Гора - недалеко от новисада, можно на элке до туда за полчаса и там такси (Или час на машине из Белграда);</li><li>Крепость Голубац - красивейшая локация для фристайла как из симуляторов, но, возможно, там нельзя летать) (2 часа);</li><li>Увац - место с глубокими каньонами и речной долиной (3,5 часа);</li><li>Национальный парк Стара Планина - горный парк с водопадами (3,5 часа);</li></ol><p>Из относительно близких:</p><ol><li>Авала - небольшие холмы с красивым видом на закатный белград (минут 30 мб).</li></ol><h2 id="покупки" tabindex="-1">Покупки <a class="header-anchor" href="#покупки" aria-label="Permalink to &quot;Покупки&quot;">​</a></h2><p>🛍️ <a href="https://docs.google.com/spreadsheets/d/19KzPUGUyeNiDDC7pDzb1e0e0x0PTzwcWPI2U6mR1TV0/edit?usp=sharing" target="_blank" rel="noreferrer">Список совместного заказа с drone-fpv-racer.com (DFR)</a></p><h3 id="гаид-как-заказывать-с-европы-и-не-платить-конские-импортные-налоги" tabindex="-1">Гайд, как заказывать с Европы и не платить конские импортные налоги <a class="header-anchor" href="#гаид-как-заказывать-с-европы-и-не-платить-конские-импортные-налоги" aria-label="Permalink to &quot;Гайд, как заказывать с Европы и не платить конские импортные налоги&quot;">​</a></h3><p>Обращаемся к DE PREVOZ. <a href="https://deprevoz.com/" target="_blank" rel="noreferrer">Их сайт</a>.</p><p>Шаги:</p><ol><li><p>Пишем Ивану в Viber (понимает на английском), чтобы получить свой адрес и данные которые надо указать на посылке. <a href="viber://add?number=381645985589" target="_blank" rel="noreferrer">Ссылка на чат для смартфона</a> и <a href="viber://chat?number=+381645985589" target="_blank" rel="noreferrer">для ПК версии</a>.</p></li><li><p>Получаем вот такую инструкцию:</p><blockquote><p>The procedure is as follows, You buy and pay online and send to our warehouse in Germany. When it arrives there in the first next tour, we bring it to Serbia. Price is from 5€ per kilogram, minimum charge 20€ for packages from 0 to 4kg. Send invoices to <a href="mailto:ukprevozin@gmail.com" target="_blank" rel="noreferrer">ukprevozin@gmail.com</a> &gt; *Note for packages outside the EU (China, America, UK, CH, Norway) that are subject to customs. You can buy only packages for which you can pay the tax online because we are no longer able to pay the tax for you.</p></blockquote></li><li><p>И вот такой адрес (в таком формате с вашими данными):</p><blockquote><p>Ordering address:</p><p>Name: ID International</p><p>Last name: SorekhovBg</p><p>Address: Osterholzallee 140 - 2.3</p><p>Postal code: 71636</p><p>City: Ludwigsburg</p><p>Phone: +4915904632469</p></blockquote></li><li><p>Вводим полученные данные при доставке (на скриншоте пример с fpv-racer&#39;а из Франции).</p></li></ol><p align="center"><img src="'+r+'" width="600" alt="пример адреса доставки с fpv-racer&#39;а из Франции, screenshot"></p><ol start="5"><li><p>Выбираем страну доставки Германия, смотрим, чтобы в при оплате в ценах был указан европейский VAT (19% вроде, чтобы не было проблем с немецкой таможней), удобный способ доставки (так как налоги уплачены - можно выбирать бесплатный dhl-express, на склад привозят за день-два).</p></li><li><p>Мониторим посылку по DHL, от того момента, как она дойдет к ним на склад - доставка до Сербии займет около недели (может быстрее, может чуть дольше, они возят машину 4 раза в месяц, ближайшие даты обычно указаны на <a href="https://deprevoz.com/datumi-polaska-html" target="_blank" rel="noreferrer">сайте</a>, но могут отличаться на день-два).</p></li><li><p>Ждем СМС на свой сербский номер (лучше не написывать Ивану в Viber, все дойдет ), который вы указали или сообщения в Viber/WhatsApp о том, что посылка пришла</p><blockquote><p>(&#39;Jutro..</p><p>Samo da proverim,dobili poruku za danasnju podelu pakete od 10h do 12h na parkingu Ekstra centra,Omladinskih brigada 100?</p><p>Nenad,pozz)</p></blockquote></li><li><p>Едем на парковку ТЦ Ekstra (Omladinskih brigada 100), идем в ее дальний от заезда конец и ищем там желтую газельку, где будут стоять два человека и раздавать посылки, платим им 20 евро или сколько получится за доставку, и уходим с посылкой.</p></li></ol>',32)])])}const g=a(l,[["render",p]]);export{u as __pageData,g as default};
